import { useState } from 'preact/hooks';

interface ResetPasswordPanelProps {
  token: string;
  onClose: () => void;
}

export function ResetPasswordPanel({ token, onClose }: ResetPasswordPanelProps) {
  const [password, setPassword] = useState('');
  const [confirm, setConfirm] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e: Event) => {
    e.preventDefault();
    if (password !== confirm) {
      setError('PASSWORDS_MISMATCH: Data integrity check failed.');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const res = await fetch('/api/auth/reset-password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token, newPassword: password }),
      });

      if (!res.ok) {
        const data = (await res.json()) as { error?: string };
        setError(data.error ?? 'RESET_FAILED: Uplink rejected.');
      } else {
        setSuccess(true);
      }
    } catch {
      setError('NETWORK_ERROR: Carrier lost.');
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div class="auth-modal-backdrop">
        <div class="auth-panel" role="dialog">
          <h3>ACCESS_RESTORED</h3>
          <p class="meta-tag" style="color: var(--color-green); margin-bottom: 1.5rem">
            CREDENTIALS_UPDATED: Your security protocol has been refreshed.
          </p>
          <button class="btn btn-primary" onClick={onClose}>
            RETURN_TO_LOGIN
          </button>
        </div>
      </div>
    );
  }

  return (
    <div
      class="auth-modal-backdrop"
      onClick={(e) => {
        if ((e.target as HTMLElement).classList.contains('auth-modal-backdrop')) onClose();
      }}
    >
      <div class="auth-panel" role="dialog">
        <h3>REESTABLISH_CREDENTIALS</h3>
        <p class="meta-tag" style="margin-bottom: 1rem">
          TOKEN_VALIDATED: Define new security sequence.
        </p>

        {error && (
          <p class="auth-error" role="alert">
            {error}
          </p>
        )}

        <form
          onSubmit={(e) => {
            void handleSubmit(e);
          }}
        >
          <div class="form-group">
            <label for="reset-password">New Password</label>
            <input
              id="reset-password"
              type="password"
              placeholder="Minimum 8 characters"
              value={password}
              onInput={(e) => {
                setPassword(e.currentTarget.value);
              }}
              required
              minLength={8}
            />
          </div>
          <div class="form-group">
            <label for="reset-confirm">Confirm Password</label>
            <input
              id="reset-confirm"
              type="password"
              placeholder="Re-enter password"
              value={confirm}
              onInput={(e) => {
                setConfirm(e.currentTarget.value);
              }}
              required
            />
          </div>
          <button type="submit" class="btn btn-primary" disabled={loading}>
            {loading ? 'PROCESSING...' : 'UPDATE_SECURITY_SEQUENCE'}
          </button>
        </form>
        <button class="btn-text" onClick={onClose}>
          CANCEL
        </button>
      </div>
    </div>
  );
}

import { mkdtemp, writeFile, rm } from 'node:fs/promises';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { describe, expect, it } from 'vitest';
import { generateScenario, GameScenarioSchema, loadScenario } from '../../bin/qa/scenario';

describe('QA scenario contract', () => {
  it('generates a schema-valid scenario with deterministic action content', () => {
    const scenario = generateScenario(42, 'classic', 20, 'bot-random', 'bot-heuristic');
    const parsed = GameScenarioSchema.parse(scenario);

    expect(parsed.version).toBe(1);
    expect(parsed.seed).toBe(42);
    expect(parsed.damageMode).toBe('classic');
    expect(parsed.startingLifepoints).toBe(20);
    expect(parsed.p1).toBe('bot-random');
    expect(parsed.p2).toBe('bot-heuristic');
    expect(parsed.actions.length).toBeGreaterThan(0);
    expect(parsed.actions[0]?.type).toBeDefined();
  });

  it('loads and validates a scenario file from disk', async () => {
    const tempDir = await mkdtemp(join(tmpdir(), 'phx-scenario-'));
    const scenarioPath = join(tempDir, 'scenario.json');
    const scenario = generateScenario(7, 'cumulative', 100, 'bot-heuristic', 'bot-heuristic');

    try {
      await writeFile(scenarioPath, `${JSON.stringify(scenario, null, 2)}\n`, 'utf8');

      const loaded = await loadScenario(scenarioPath);
      expect(loaded).toEqual(GameScenarioSchema.parse(scenario));
    } finally {
      await rm(tempDir, { recursive: true, force: true });
    }
  });
});

import { buildApp } from '../src/app.js';
import * as fs from 'node:fs/promises';
import * as path from 'node:path';

async function main() {
  // Build the app without binding to a port
  const app = await buildApp();
  await app.ready();

  // Extract the route tree from Fastify
  const routesText = app.printRoutes();

  const docPath = path.resolve(process.cwd(), '../docs/reference/api-routes.txt');

  // Ensure directory exists
  await fs.mkdir(path.dirname(docPath), { recursive: true });

  // Write to a text file
  await fs.writeFile(docPath, routesText, 'utf8');
  console.log(`✅ Routes dumped to ${docPath}`);

  await app.close();
}

main()
  .then(() => process.exit(0))
  .catch((err) => {
    console.error('Failed to dump routes:', err);
    process.exit(1);
  });

import { createHash } from 'node:crypto';
import { readdirSync, readFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));

export const MIGRATIONS_DIR = resolve(__dirname, '../../migrations');
export const MIGRATIONS_TABLE = 'schema_migrations';

export interface MigrationFile {
  name: string;
  checksum: string;
  path: string;
  statements: string[];
}

function checksum(text: string): string {
  return createHash('sha256').update(text, 'utf8').digest('hex');
}

function splitStatements(sqlText: string): string[] {
  return sqlText
    .split('--> statement-breakpoint')
    .map((statement) => statement.trim())
    .filter(Boolean)
    .map((statement) => statement.replace(/;$/u, '').trim())
    .filter(Boolean);
}

export function loadMigrationFiles(): MigrationFile[] {
  const names = readdirSync(MIGRATIONS_DIR)
    .filter((entry) => entry.endsWith('.sql'))
    .sort((a, b) => a.localeCompare(b));

  return names.map((name) => {
    const path = resolve(MIGRATIONS_DIR, name);
    const contents = readFileSync(path, 'utf8');
    return {
      name,
      checksum: checksum(contents),
      path,
      statements: splitStatements(contents),
    };
  });
}

import './instrument.js';
import { buildApp } from './app.js';
import { checkPendingMigrations } from './db/check-migrations.js';
import { spawn } from 'node:child_process';
import { openSync } from 'node:fs';
import { resolve } from 'node:path';

// Intercept daemon flag before doing anything else
if (process.argv.includes('--daemon')) {
  const outLog = resolve(process.cwd(), 'phalanx-server.out.log');
  const errLog = resolve(process.cwd(), 'phalanx-server.err.log');
  const out = openSync(outLog, 'a');
  const err = openSync(errLog, 'a');

  // Strip "--daemon" to prevent infinite spawning loop
  const args = process.argv.slice(1).filter((arg) => arg !== '--daemon');

  const command: string = process.argv[0] ?? 'node';
  const child = spawn(command, args, {
    detached: true,
    stdio: ['ignore', out, err],
    env: process.env,
  });

  child.unref();
  console.log(`Phalanx Duel server started in daemon mode (PID: ${child.pid})`);
  console.log(`STDOUT -> ${outLog}`);
  console.log(`STDERR -> ${errLog}`);
  process.exit(0);
}

async function main(): Promise<void> {
  await checkPendingMigrations();
  let app = await buildApp();
  const port = parseInt(process.env.PHALANX_SERVER_PORT ?? '3001', 10);
  const host = process.env.HOST ?? '0.0.0.0';

  await app.listen({ port, host });
  console.log(`Phalanx Duel server listening on http://${host}:${port}`);

  // ── Graceful Shutdown Handler ────────────────────────────────────
  // When the container receives SIGTERM (Kubernetes, Docker stop, Fly.io deploy),
  // close the server gracefully, allowing in-flight requests/WebSocket connections
  // to complete within a timeout window.
  //
  // Timeline:
  // 1. Signal received → Stop accepting NEW connections
  // 2. Close server → Wait for in-flight requests (30s timeout)
  // 3. Exit → Process terminates, container restarts
  const shutdownSignals = ['SIGTERM', 'SIGINT', 'SIGQUIT'];
  const reloadSignals = ['SIGHUP', 'SIGUSR2'];

  shutdownSignals.forEach((signal) => {
    process.on(
      signal,
      () =>
        void (async () => {
          app.log.info(`Received ${signal}, initiating graceful shutdown...`);

          try {
            await app.close();
            app.log.info('Server closed successfully, all connections drained');
            process.exit(0);
          } catch (err) {
            app.log.error(
              { error: err instanceof Error ? err.message : String(err) },
              'Error during graceful shutdown',
            );
            process.exit(1);
          }
        })(),
    );
  });

  reloadSignals.forEach((signal) => {
    process.on(
      signal,
      () =>
        void (async () => {
          app.log.info(`Received ${signal}, initiating configuration reload...`);

          try {
            await app.close();
            app.log.info('Server closed. Reloading environment variables from configuration...');

            // Re-evaluate configuration manually
            const { loadAllEnvs } = await import('./loadEnv.js');
            loadAllEnvs();

            app = await buildApp();
            const port = parseInt(process.env.PHALANX_SERVER_PORT ?? '3001', 10);
            const host = process.env.HOST ?? '0.0.0.0';

            await app.listen({ port, host });
            app.log.info(`Phalanx Duel server re-listening on http://${host}:${port}`);
          } catch (err) {
            app.log.error(
              { error: err instanceof Error ? err.message : String(err) },
              'Error during configuration reload',
            );
            process.exit(1);
          }
        })(),
    );
  });

  // Handle uncaught exceptions → log and exit
  process.on('uncaughtException', (err) => {
    app.log.error(
      { error: err instanceof Error ? err.message : String(err) },
      'Uncaught exception, exiting',
    );
    process.exit(1);
  });

  // Handle unhandled promise rejections → log and exit
  process.on('unhandledRejection', (reason) => {
    app.log.error({ reason }, 'Unhandled rejection, exiting');
    process.exit(1);
  });
}

main().catch((err: unknown) => {
  console.error('Failed to start server:', err);
  process.exit(1);
});
